                        intermediateStorageRule struct {
                                ID               string
                                NamespaceKey     string
                                FlagKey          string
                                SegmentKey       string
                                SegmentMatchType flipt.MatchType
                                SegmentOperator  flipt.SegmentOperator
                                Rank             int32
                        }
                        optionalConstraint optionalConstraint
                )

