                                UpdatedAt:    ss.now,
                        }

                        if rollout.Threshold != nil {
                                s.Threshold = &storage.RolloutThreshold{
                                        Percentage: rollout.Threshold.Percentage,
                                        Value:      rollout.Threshold.Value,
                                }
                                s.RolloutType = flipt.RolloutType_THRESHOLD_ROLLOUT_TYPE

