                                        constraints := make([]storage.EvaluationConstraint, 0, len(segment.Constraints))
                                        for _, c := range segment.Constraints {
                                                constraints = append(constraints, storage.EvaluationConstraint{
                                                        Operator: c.Operator,
                                                        Property: c.Property,
                                                        Type:     c.Type,
                                                        Value:    c.Value,
