	PageToken string
	Limit     uint64
	Order     Order
	Offset    uint64
}

// Normalize sets default values for unset query parameters.
func (q *QueryParams) Normalize() {
	if q.Order == "" {
		q.Order = OrderAsc
	}
}

// ListRequest is a generic list request combining a predicate with query parameters.
type ListRequest[P any] struct {
	Predicate   P
	QueryParams QueryParams
}

// ResultSet is a generic result set returned from list operations.
type ResultSet[V any] struct {
	Results       []V
	NextPageToken string
}

