type QueryOption = containers.Option[QueryParams]

// ListOption is a functional option for a ListRequest with predicate type P.
type ListOption[P any] = containers.Option[ListRequest[P]]

// WithReference returns an option that sets the Reference on a ReferenceRequest.
// It is accepted by NewNamespace, NewResource, and NewID constructors.
func WithReference(ref string) containers.Option[ReferenceRequest] {
	return func(r *ReferenceRequest) {
		r.Reference = Reference(ref)
	}
}

// WithPageToken returns a QueryOption that sets the page token.
func WithPageToken(token string) QueryOption {
	return func(q *QueryParams) {
		q.PageToken = token
	}
}

// WithOrder returns a QueryOption that sets the sort order.
func WithOrder(order Order) QueryOption {
	return func(q *QueryParams) {
		q.Order = order
	}
}

// WithLimit returns a QueryOption that sets the page size limit.
func WithLimit(n uint64) QueryOption {
	return func(q *QueryParams) {
		q.Limit = n
	}
}

// WithOffset returns a QueryOption that sets the page offset.
func WithOffset(n uint64) QueryOption {
	return func(q *QueryParams) {
		q.Offset = n
	}
}

// NewNamespace constructs a NamespaceRequest for the given namespace key.
func NewNamespace(ns string, opts ...containers.Option[ReferenceRequest]) NamespaceRequest {
	r := NamespaceRequest{namespaceKey: ns}
	containers.ApplyAll(&r.ReferenceRequest, opts...)
	return r
}

// NewResource constructs a ResourceRequest for the given namespace and resource key.
func NewResource(ns, key string, opts ...containers.Option[ReferenceRequest]) ResourceRequest {
	r := ResourceRequest{
		NamespaceRequest: NamespaceRequest{namespaceKey: ns},
		Key:              key,
	}
	containers.ApplyAll(&r.ReferenceRequest, opts...)
	return r
}

// NewID constructs an IDRequest for the given ID.
func NewID(id string, opts ...containers.Option[ReferenceRequest]) IDRequest {
	r := IDRequest{ID: id}
	containers.ApplyAll(&r.ReferenceRequest, opts...)
	return r
}

